using System;using System.Linq;class A{static void Main(){var p=Console.ReadLine().Split();int W=int.Parse(p[0]),H=int.Parse(p[1]);var img=Console.ReadLine().Split();var D=new byte[W*H];var DC=new byte[W*H];int pi=0;for(int i=0;i<img.Length;i+=2){byte c=(byte)(img[i][0]=='B'?1:0);int l=int.Parse(img[i+1]);for(int j=0;j<l;j++){D[pi]=c;DC[pi]=c;pi++;}}int sc=0;while(sc<W){bool f=false;for(int r=0;r<H;r++)if(D[r*W+sc]==1)f=true;if(f)break;sc++;}int ec=W-1;while(ec>0){bool f=false;for(int r=0;r<H;r++)if(D[r*W+ec]==1)f=true;if(f)break;ec--;}var ls=new int[5];var le=new int[5];int nl=0,r2=0;while(r2<H){if(D[r2*W+sc]==1){ls[nl]=r2;while(r2<H&&D[r2*W+sc]==1)r2++;le[nl]=r2-1;nl++;}r2++;}int dbl=ls[1]-le[0]-1,lw=le[0]-ls[0]+1;for(int i=0;i<5;i++)for(int r=ls[i];r<=le[i];r++)for(int c=0;c<W;c++)D[r*W+c]=0;for(int r=ls[4]+dbl+lw;r<=le[4]+lw+dbl&&r<H;r++)for(int c=0;c<W;c++)D[r*W+c]=0;var NY=new double[12];NY[0]=(ls[4]+le[4])/2.0+dbl;NY[1]=(ls[4]+le[4])/2.0+dbl/2.0;NY[2]=(ls[4]+le[4])/2.0;NY[3]=(ls[4]+le[3])/2.0;NY[4]=(ls[3]+le[3])/2.0;NY[5]=(ls[3]+le[2])/2.0;NY[6]=(ls[2]+le[2])/2.0;NY[7]=(ls[2]+le[1])/2.0;NY[8]=(ls[1]+le[1])/2.0;NY[9]=(ls[1]+le[0])/2.0;NY[10]=(ls[0]+le[0])/2.0;NY[11]=(ls[0]+le[0])/2.0-dbl/2.0;string P="CDEFGABCDEFG";var nv=new int[W];for(int c=0;c<W;c++){int n=0;for(int r=0;r<H;r++)if(D[r*W+c]==1)n++;nv[c]=n;}var ns=new int[1000];var ne=new int[1000];int nn=0;bool pv=false;int cc=sc;while(cc<=ec){if(nv[cc]==nv[sc]){if(pv&&nn>0)ne[nn-1]=cc;while(cc<=ec&&nv[cc]==nv[sc])cc++;ns[nn]=cc;nn++;pv=true;}cc++;}nn--;for(int c=0;c<W;c++)if(nv[c]>dbl)for(int r=0;r<H;r++)D[r*W+c]=0;var res=new System.Text.StringBuilder();for(int i=0;i<nn;i++){int w=0;double cy=0;for(int c=ns[i];c<=ne[i];c++)for(int r=0;r<H;r++)if(D[r*W+c]==1){w++;cy+=r;}cy/=w;int sr=(int)Math.Round(cy),sm=(ns[i]+ne[i])/2;char tp=DC[sr*W+sm]==1?'Q':'H';double md=1e9;int px=0;for(int j=0;j<12;j++){double d=Math.Abs(cy-NY[j]);if(d<md){md=d;px=j;}}if(i>0)res.Append(' ');res.Append(P[px]);res.Append(tp);}Console.WriteLine(res);}}